// ============================================================
// Mapeia item da API oficial do ML -> MDX + JSON normalizado
// ============================================================

const AFFILIATE_ID = $env.ML_AFFILIATE_ID || 'UNIDICASOFERTAS';
const PROJECT_PATH = $env.UNIDICAS_PROJECT_PATH || 'C:\\Users\\Sinval\\Projetos\\unidicas';
const DESCONTO_MIN_PCT = Number($env.DESCONTO_MIN_PCT || 15);

function slugify(s) {
  return String(s || '')
    .toLowerCase()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/(^-|-$)/g, '')
    .slice(0, 80);
}

function escapeYaml(s) {
  return String(s == null ? '' : s).replace(/"/g, '\\"');
}

function formatBRL(n) {
  const num = Number(n);
  if (!Number.isFinite(num)) return '0';
  return num.toLocaleString('pt-BR', { minimumFractionDigits: 0 });
}

function stableSlug(mlbId, titulo) {
  const t = slugify(titulo).slice(0, 50);
  return t ? `${t}-${mlbId.toLowerCase()}` : mlbId.toLowerCase();
}

function fullImage(thumbUrl) {
  if (!thumbUrl) return '';
  return thumbUrl
    .replace('-I.jpg', '-O.jpg')
    .replace('-I-W250.jpg', '-O.jpg')
    .replace('-I-W200.jpg', '-O.jpg')
    .replace('-I-W100.jpg', '-O.jpg')
    .replace('-I-W50.jpg', '-O.jpg');
}

function mlbToSiteCategory(mlbId, hint) {
  const map = {
    MLB1051: 'notebooks',
    MLB1648: 'celulares',
    MLB1574: 'fones',
    MLB1132: 'smartwatches',
    MLB120314: 'air-fryers',
    MLB5726: 'eletrodomesticos',
  };
  if (map[mlbId]) return map[mlbId];
  if (hint) return hint;
  return 'outros';
}

const item = $input.first().json;
const sheetRow = $('Ler Google Sheets').item.json;
const mlbId = String(item.id || sheetRow.mlb_id);

if (!item || !item.id) {
  throw new Error(`Item sem ID. Resposta: ${JSON.stringify(item).slice(0, 200)}`);
}

const titulo = item.title || sheetRow.categoria || mlbId;
const slug = stableSlug(mlbId, titulo);

const preco = Number(item.price);
const precoOriginal = Number(item.original_price || preco);

if (!Number.isFinite(preco) || preco <= 0) {
  throw new Error(`Preco invalido para ${mlbId}: ${preco}`);
}

const descontoPct = precoOriginal > preco
  ? Math.round((1 - preco / precoOriginal) * 100)
  : 0;

if (descontoPct < DESCONTO_MIN_PCT) {
  return [{ json: { descartado: true, motivo: `desconto ${descontoPct}% < ${DESCONTO_MIN_PCT}%`, mlbId } }];
}

const condicao = item.condition === 'new' ? 'novo' : 'usado';
const estoque = Number(item.available_quantity || 0);
const semEstoque = estoque <= 0;

if (semEstoque) {
  return [{ json: { descartado: true, motivo: 'sem estoque', mlbId } }];
}

const freteGratis = !!(item.shipping && item.shipping.free_shipping);
const parcels = item.installments
  ? `${item.installments.quantity}x R$ ${formatBRL(item.installments.amount)}`
  : null;

const cupom = sheetRow.cupom || undefined;
const imagem = fullImage(item.secure_thumbnail || item.thumbnail);

const separator = item.permalink.includes('?') ? '&' : '?';
const linkAfiliado = `${item.permalink}${separator}matt_word=${AFFILIATE_ID}&matt_tool=${AFFILIATE_ID}`;

const categoriaSlug = mlbToSiteCategory(item.category_id, sheetRow.categoria_slug);
const expiraEm = new Date(Date.now() + 6 * 60 * 60 * 1000).toISOString().slice(0, 10);

const pros = [
  `De R$ ${formatBRL(precoOriginal)} por R$ ${formatBRL(preco)}`,
  `Desconto de ${descontoPct}%`,
  condicao === 'novo' ? 'Produto novo' : null,
  freteGratis ? 'Frete gratis (Full)' : null,
  parcels ? `Parcelado em ${parcels}` : null,
  estoque < 10 ? `Estoque baixo: ${estoque} unidade(s)` : null,
].filter(Boolean);

const contras = [
  sheetRow.cupom ? 'Cupom aplicavel no carrinho' : null,
].filter(Boolean);

const prosYaml = pros.map(p => `  - "${escapeYaml(p)}"`).join('\n');
const contrasYaml = contras.length
  ? `contras:\n${contras.map(c => `  - "${escapeYaml(c)}"`).join('\n')}`
  : `contras: []`;

const tags = ['oferta-ml', categoriaSlug];
if (freteGratis) tags.push('frete-gratis');
if (descontoPct >= 30) tags.push('super-oferta');

const resumo = `${titulo} por R$ ${formatBRL(preco)} (era R$ ${formatBRL(precoOriginal)}, -${descontoPct}%).`;

const mdx = `---
slug: "${slug}"
titulo: "${escapeYaml(titulo)} - ${descontoPct}% OFF"
produto: "${escapeYaml(titulo)}"
categoria: "${categoriaSlug}"
nota: 4.0
imagem: "${imagem}"
marketplace: "Mercado Livre"
preco: ${preco}
precoOriginal: ${precoOriginal}
linkAfiliado: "${linkAfiliado}"${cupom ? `\ncupom: "${escapeYaml(cupom)}"` : ''}
pros:
${prosYaml}
${contrasYaml}
resumo: "${escapeYaml(resumo)}"
emDestaque: ${descontoPct >= 30}
atributos:
  preco: ${preco}
  desconto: ${descontoPct}
expiraEm: "${expiraEm}"
tags:
${tags.map(t => `  - "${t}"`).join('\n')}
---

## ${titulo} com ${descontoPct}% de desconto

<ProTip>Oferta capturada automaticamente do **Mercado Livre** em ${new Date().toLocaleString('pt-BR')}. O preco pode ter mudado - confirme na pagina do vendedor antes de comprar.</ProTip>

<Warning>Precos e estoque do Mercado Livre mudam rapidamente. Esta oferta pode expirar a qualquer momento.</Warning>

**Por que esta oferta entrou na lista:**

- **Desconto de ${descontoPct}%**: de R$ ${formatBRL(precoOriginal)} por R$ ${formatBRL(preco)}
${pros.slice(1).map(p => `- ${p}`).join('\n')}

[Ver oferta no Mercado Livre](${linkAfiliado})
`;

const json = {
  id: mlbId,
  slug,
  titulo,
  categoria_id: item.category_id,
  categoria_slug: categoriaSlug,
  preco_de: precoOriginal,
  preco_por: preco,
  desconto: descontoPct,
  estoque,
  condicao,
  frete_gratis: freteGratis,
  parcelas: parcels,
  cupom: cupom || null,
  link_afiliado: linkAfiliado,
  imagem,
  seller: item.seller_id ? { id: item.seller_id } : undefined,
  data_postagem: new Date().toISOString(),
};

return [{
  json: {
    slug,
    mlbId,
    mdPath: `${PROJECT_PATH}\\src\\content\\ofertas\\${slug}.mdx`,
    jsonPath: `${PROJECT_PATH}\\content\\produtos\\${mlbId}.json`,
    mdx,
    jsonContent: JSON.stringify(json, null, 2),
    titulo,
    preco,
    precoOriginal,
    descontoPct,
    linkAfiliado,
  }
}];
